const { execSync } = require('child_process');
const fs = require('fs');

function proxmoxGet(apiPath) {
  const url = process.env.PROXMOX_URL;
  const nodeName = process.env.PROXMOX_NODE;
  const tokenId = process.env.PROXMOX_TOKEN_ID;
  const tokenSecret = process.env.PROXMOX_TOKEN_SECRET;
  const fullUrl = url + '/api2/json/nodes/' + nodeName + apiPath;
  const auth = 'PVEAPIToken=' + tokenId + '=' + tokenSecret;
  const script = `const https=require('https');const u=new URL('${fullUrl}');https.get({hostname:u.hostname,port:u.port,path:u.pathname,headers:{Authorization:'${auth}'},rejectUnauthorized:false,timeout:10000},r=>{let d='';r.on('data',c=>d+=c);r.on('end',()=>process.stdout.write(d))}).on('error',e=>process.stdout.write(JSON.stringify({error:e.message})));`;
  fs.writeFileSync('/tmp/_pve_q.js', script);
  try {
    const raw = execSync('node /tmp/_pve_q.js', { encoding: 'utf-8', timeout: 15000 });
    return JSON.parse(raw);
  } catch(e) {
    return { error: e.message };
  }
}

const url = process.env.PROXMOX_URL;
if (!url) return [{ json: { vms: [], error: 'PROXMOX_URL not configured in .env' } }];

try {
  const data = proxmoxGet('/qemu');
  if (data.error) return [{ json: { vms: [], error: data.error } }];

  const vms = (data.data || [])
    .filter(vm => vm.vmid >= 200 && vm.vmid < 300)
    .map(vm => ({
      vmid: vm.vmid,
      name: vm.name || 'vm-' + vm.vmid,
      status: vm.status,
      ip: null,
      uptime: vm.uptime || 0,
      tags: vm.tags || ''
    }));

  for (const vm of vms) {
    if (vm.status !== 'running') continue;
    try {
      const agentData = proxmoxGet('/qemu/' + vm.vmid + '/agent/network-get-interfaces');
      if (agentData && agentData.data && agentData.data.result) {
        for (const iface of agentData.data.result) {
          if (iface.name === 'lo' || iface.name === 'Loopback Pseudo-Interface 1') continue;
          const addrs = iface['ip-addresses'] || [];
          const ipv4 = addrs.find(a => a['ip-address-type'] === 'ipv4' && !a['ip-address'].startsWith('127.'));
          if (ipv4) { vm.ip = ipv4['ip-address']; break; }
        }
      }
    } catch(e) { }
  }

  return [{ json: { vms } }];
} catch(e) {
  return [{ json: { vms: [], error: e.message } }];
}

const { execSync } = require('child_process');
